import{f as i,D as E,o as d,c as h,a2 as o,b as e,w as a,a as s,G as n,a5 as l}from"./chunks/framework.DHYrF-q6.js";const m=JSON.parse('{"title":"数据与模型管理","description":"","frontmatter":{},"headers":[],"relativePath":"ai-product-manager/data-model-management.md","filePath":"ai-product-manager/data-model-management.md","lastUpdated":1781090728000}'),u={name:"ai-product-manager/data-model-management.md"};function p(A,t,q,g,b,B){const r=E("Mermaid");return d(),h("div",null,[t[2]||(t[2]=o('<h1 id="数据与模型管理" tabindex="-1">数据与模型管理 <a class="header-anchor" href="#数据与模型管理" aria-label="Permalink to &quot;数据与模型管理&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>数据是 AI 产品的燃料，模型是引擎。<strong>AI 产品经理的核心增量价值之一，就是构建从数据到模型的完整闭环</strong>。本章从数据采集标注、特征工程、模型评估调优、数据闭环四个维度，建立 PM 视角下的数据与模型管理能力。</p><div class="tip custom-block"><p class="custom-block-title">学习目标</p><p>理解数据标注规范设计、模型评估方法论、数据漂移监控机制，能主导 AI 产品的数据策略。</p></div><hr><h2 id="一、知识图谱" tabindex="-1">一、知识图谱 <a class="header-anchor" href="#一、知识图谱" aria-label="Permalink to &quot;一、知识图谱&quot;">​</a></h2>',6)),(d(),e(l,null,{default:a(()=>[n(r,{id:"mermaid-18",class:"mermaid",graph:"mindmap%0A%20%20root((%E6%95%B0%E6%8D%AE%E4%B8%8E%E6%A8%A1%E5%9E%8B%E7%AE%A1%E7%90%86))%0A%20%20%20%20%E6%95%B0%E6%8D%AE%E9%87%87%E9%9B%86%E4%B8%8E%E6%A0%87%E6%B3%A8%0A%20%20%20%20%20%20%E6%95%B0%E6%8D%AE%E6%BA%90%E8%AF%84%E4%BC%B0%0A%20%20%20%20%20%20%E6%A0%87%E6%B3%A8%E8%A7%84%E8%8C%83%E8%AE%BE%E8%AE%A1%0A%20%20%20%20%20%20%E8%B4%A8%E9%87%8F%E6%8E%A7%E5%88%B6%0A%20%20%20%20%20%20%E6%95%B0%E6%8D%AE%E5%A2%9E%E5%BC%BA%0A%20%20%20%20%20%20%E6%95%B0%E6%8D%AE%E9%9B%86%E5%88%92%E5%88%86%0A%20%20%20%20%E7%89%B9%E5%BE%81%E5%B7%A5%E7%A8%8B%0A%20%20%20%20%20%20%E7%89%B9%E5%BE%81%E9%80%89%E6%8B%A9%0A%20%20%20%20%20%20%E6%95%B0%E6%8D%AE%E6%B8%85%E6%B4%97%0A%20%20%20%20%20%20%E6%95%B0%E6%8D%AE%E8%B4%A8%E9%87%8F%E5%B7%A1%E6%A3%80%0A%20%20%20%20%20%20%E6%95%B0%E6%8D%AE%E7%89%88%E6%9C%AC%E7%AE%A1%E7%90%86%0A%20%20%20%20%E6%A8%A1%E5%9E%8B%E8%AF%84%E4%BC%B0%E4%B8%8E%E8%B0%83%E4%BC%98%0A%20%20%20%20%20%20%E7%A6%BB%E7%BA%BF%20vs%20%E5%9C%A8%E7%BA%BF%E8%AF%84%E4%BC%B0%0A%20%20%20%20%20%20%E8%AF%AF%E5%B7%AE%E5%88%86%E6%9E%90%0A%20%20%20%20%20%20%E8%B6%85%E5%8F%82%E6%95%B0%E8%B0%83%E4%BC%98%0A%20%20%20%20%20%20%E6%A8%A1%E5%9E%8B%E5%8E%8B%E7%BC%A9%0A%20%20%20%20%E6%95%B0%E6%8D%AE%E9%97%AD%E7%8E%AF%0A%20%20%20%20%20%20%E6%95%B0%E6%8D%AE%E6%BC%82%E7%A7%BB%E6%A3%80%E6%B5%8B%0A%20%20%20%20%20%20%E6%A8%A1%E5%9E%8B%E7%9B%91%E6%8E%A7%0A%20%20%20%20%20%20%E5%86%8D%E8%AE%AD%E7%BB%83%E8%A7%A6%E5%8F%91%0A%20%20%20%20%20%20%E5%8F%8D%E9%A6%88%E5%9B%9E%E6%B5%81%0A"})]),fallback:a(()=>[...t[0]||(t[0]=[s(" Loading... ",-1)])]),_:1})),t[3]||(t[3]=o('<hr><h2 id="二、数据采集与标注" tabindex="-1">二、数据采集与标注 <a class="header-anchor" href="#二、数据采集与标注" aria-label="Permalink to &quot;二、数据采集与标注&quot;">​</a></h2><h3 id="_2-1-数据是-ai-产品的第一大成本" tabindex="-1">2.1 数据是 AI 产品的第一大成本 <a class="header-anchor" href="#_2-1-数据是-ai-产品的第一大成本" aria-label="Permalink to &quot;2.1 数据是 AI 产品的第一大成本&quot;">​</a></h3><p>在 AI 产品开发中，数据阶段的投入通常占总工作量的 <strong>40%-50%</strong>。这不是技术问题，而是产品管理问题。</p><table tabindex="0"><thead><tr><th>数据来源</th><th>优点</th><th>缺点</th><th>PM 注意事项</th></tr></thead><tbody><tr><td><strong>自有业务数据</strong></td><td>免费、贴合场景</td><td>可能有偏差、质量参差</td><td>业务数据不等于训练数据——需要清洗和标注</td></tr><tr><td><strong>公开数据集</strong></td><td>低成本、可快速启动</td><td>与业务场景有 Gap</td><td>适合 POC 阶段，不适合上线</td></tr><tr><td><strong>采购数据</strong></td><td>专业标注、质量可控</td><td>成本高（每条几毛到几块钱）、周期长</td><td>明确标注规范和验收标准是 PM 的活</td></tr><tr><td><strong>用户交互数据</strong></td><td>自动收集、持续增长</td><td>隐私合规、需要脱敏</td><td>设计产品时就要嵌入数据采集点</td></tr></tbody></table><h3 id="_2-2-标注规范设计——ai-pm-的核心交付物" tabindex="-1">2.2 标注规范设计——AI PM 的核心交付物 <a class="header-anchor" href="#_2-2-标注规范设计——ai-pm-的核心交付物" aria-label="Permalink to &quot;2.2 标注规范设计——AI PM 的核心交付物&quot;">​</a></h3><div class="warning custom-block"><p class="custom-block-title">面试追问</p><p><strong>Q: 设计一份标注规范的思路是什么？请以&quot;用户评价情感分析&quot;为例。</strong></p><p><strong>A:</strong> 标注规范不是&quot;正/中/负&quot;三个标签就完了。以下是完整的设计思路：</p><p><strong>一、定义标签体系</strong></p><ul><li>正面：明确的好评或满意度表达。例：&quot;很好用&quot;、&quot;不错，推荐&quot;</li><li>中性：客观描述或模糊表达。例：&quot;还行吧&quot;、&quot;用了三天了&quot;</li><li>负面：明确的差评或不满表达。例：&quot;太难用了&quot;、&quot;质量不行&quot;</li><li><strong>重要</strong>：混合评价归为哪一类？&quot;物流快但质量差&quot;——这个归&quot;负面&quot;（以最终满意度为准），并在规范里明确说明这个规则。</li></ul><p><strong>二、定义边界 Case（这是最容易出问题的地方）</strong></p><table tabindex="0"><thead><tr><th>文本</th><th>标注</th><th>原因</th></tr></thead><tbody><tr><td>&quot;还行吧&quot;</td><td>中性</td><td>无明显正/负倾向</td></tr><tr><td>&quot;还行吧，就那样&quot;</td><td>中性</td><td>同上</td></tr><tr><td>&quot;还行吧！强烈推荐！&quot;</td><td>正面</td><td>&quot;强烈推荐&quot;是最强信号</td></tr><tr><td>&quot;质量还行，客服差&quot;</td><td>负面</td><td>以&quot;客服差&quot;为主要情绪</td></tr><tr><td>纯表情&quot;😂&quot;</td><td>正面</td><td>上下文无负面语义</td></tr><tr><td>反讽&quot;真棒，第三天就坏了&quot;</td><td>负面</td><td>这是反讽，实际意思是负面</td></tr></tbody></table><p><strong>三、质量控制</strong></p><ul><li>一致性检验：同一个样本让两个标注员分别标，计算 Kappa 系数。Kappa &lt; 0.7 说明标注规范不够清晰或标注员理解不一致。</li><li>黄金集校准：准备 100 条已确认标注的&quot;标准答案&quot;样本，标注员入职前必须通过黄金集测试（准确率 &gt; 95%）。</li></ul><p><strong>四、标注成本估算</strong></p><p>这个需求如果外包给标注公司，每条大概 0.2-0.5 元。你需要 10000 条训练数据 + 2000 条测试数据，大概 3000-6000 元 + 两周周转。</p></div><h3 id="_2-3-训练集-验证集-测试集划分" tabindex="-1">2.3 训练集/验证集/测试集划分 <a class="header-anchor" href="#_2-3-训练集-验证集-测试集划分" aria-label="Permalink to &quot;2.3 训练集/验证集/测试集划分&quot;">​</a></h3><table tabindex="0"><thead><tr><th>数据集</th><th>用途</th><th>典型比例</th><th>PM 关注点</th></tr></thead><tbody><tr><td><strong>训练集</strong></td><td>用于训练模型参数</td><td>70%</td><td>数据量是否足够？类别分布是否均衡？</td></tr><tr><td><strong>验证集</strong></td><td>训练过程中调超参数用</td><td>15%</td><td>不能偷看验证集——会导致过拟合验证集</td></tr><tr><td><strong>测试集</strong></td><td>最终评估模型性能</td><td>15%</td><td>测试集必须与训练集完全隔离，不能&quot;污染&quot;</td></tr></tbody></table><p><strong>常见错误</strong>：训练集、验证集、测试集不是随机切分就完了。你需要确保三个集的数据分布一致——比如按时间切分（训练集用 Q1 数据，测试集用 Q2 数据），避免&quot;用未来数据预测过去&quot;。</p><hr><h2 id="三、模型评估与调优" tabindex="-1">三、模型评估与调优 <a class="header-anchor" href="#三、模型评估与调优" aria-label="Permalink to &quot;三、模型评估与调优&quot;">​</a></h2><h3 id="_3-1-误差分析——ai-pm-最重要的分析能力" tabindex="-1">3.1 误差分析——AI PM 最重要的分析能力 <a class="header-anchor" href="#_3-1-误差分析——ai-pm-最重要的分析能力" aria-label="Permalink to &quot;3.1 误差分析——AI PM 最重要的分析能力&quot;">​</a></h3><p>模型上线前的评估不只是看一个数值，而是深度分析&quot;模型在什么地方做错了&quot;。</p>',14)),(d(),e(l,null,{default:a(()=>[n(r,{id:"mermaid-326",class:"mermaid",graph:"graph%20TD%0A%20%20%20%20A%5B%E6%A8%A1%E5%9E%8B%E9%A2%84%E6%B5%8B%E7%BB%93%E6%9E%9C%5D%20--%3E%20B%5B%E6%B7%B7%E6%B7%86%E7%9F%A9%E9%98%B5%E5%88%86%E6%9E%90%5D%0A%20%20%20%20B%20--%3E%20C%7B%E5%81%87%E9%98%B3%E6%80%A7%20FP%20%E9%9B%86%E4%B8%AD%E5%9C%A8%E5%93%AA%3F%7D%0A%20%20%20%20B%20--%3E%20D%7B%E5%81%87%E9%98%B4%E6%80%A7%20FN%20%E9%9B%86%E4%B8%AD%E5%9C%A8%E5%93%AA%3F%7D%0A%20%20%20%20C%20--%3E%20E%5B%E8%AF%AF%E6%8A%A5%E5%9C%BA%E6%99%AF%E5%88%86%E6%9E%90%5D%0A%20%20%20%20D%20--%3E%20F%5B%E6%BC%8F%E6%8A%A5%E5%9C%BA%E6%99%AF%E5%88%86%E6%9E%90%5D%0A%20%20%20%20E%20--%3E%20G%5B%E4%BC%98%E5%8C%96%E6%96%B9%E5%90%911%3A%3Cbr%2F%3E%E6%8F%90%E9%AB%98%E7%B2%BE%E7%A1%AE%E7%8E%87%5D%0A%20%20%20%20F%20--%3E%20H%5B%E4%BC%98%E5%8C%96%E6%96%B9%E5%90%912%3A%3Cbr%2F%3E%E6%8F%90%E9%AB%98%E5%8F%AC%E5%9B%9E%E7%8E%87%5D%0A"})]),fallback:a(()=>[...t[1]||(t[1]=[s(" Loading... ",-1)])]),_:1})),t[4]||(t[4]=o(`<p><strong>实战方法</strong>：</p><ol><li>拉出 100 条 Bad Case（模型预测错误的样本）</li><li>人工分类这些 Bad Case 的&quot;错误原因&quot;：是标注错误？是模型能力不足？还是输入数据有问题？</li><li>统计各类原因的占比，优先解决占比最高的那类</li></ol><h3 id="_3-2-模型升级决策——要不要换更大的模型" tabindex="-1">3.2 模型升级决策——要不要换更大的模型？ <a class="header-anchor" href="#_3-2-模型升级决策——要不要换更大的模型" aria-label="Permalink to &quot;3.2 模型升级决策——要不要换更大的模型？&quot;">​</a></h3><table tabindex="0"><thead><tr><th>场景</th><th>小模型（BERT/TinyLLM）</th><th>大模型（GPT-4o）</th><th>决策依据</th></tr></thead><tbody><tr><td>简单分类</td><td>85% 准确率，成本极低</td><td>92% 准确率，成本高</td><td>多 7 个点的提升值不值成本差异？</td></tr><tr><td>复杂推理</td><td>60% 准确率（基本不可用）</td><td>88% 准确率</td><td>小模型压根不够用，必须上大模型</td></tr><tr><td>高并发（10000 QPS）</td><td>轻松应对</td><td>成本爆炸</td><td>用大模型做标注/训练，用小模型上线推理</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">实战原则</p><p><strong>大模型当老师，小模型当打工人。</strong> 用 GPT-4o 生成高质量训练数据 + 做人评，用精调后的小模型上线服务。这是目前业界性价比最高的方案。</p></div><hr><h2 id="四、数据闭环——ai-产品上线后的核心工作" tabindex="-1">四、数据闭环——AI 产品上线后的核心工作 <a class="header-anchor" href="#四、数据闭环——ai-产品上线后的核心工作" aria-label="Permalink to &quot;四、数据闭环——AI 产品上线后的核心工作&quot;">​</a></h2><h3 id="_4-1-数据漂移监控" tabindex="-1">4.1 数据漂移监控 <a class="header-anchor" href="#_4-1-数据漂移监控" aria-label="Permalink to &quot;4.1 数据漂移监控&quot;">​</a></h3><p>数据漂移是 AI 产品&quot;上线后死亡&quot;的第一原因——模型在训练集上表现完美，上线后表现持续下降。</p><table tabindex="0"><thead><tr><th>漂移类型</th><th>含义</th><th>检测方法</th><th>产品案例</th></tr></thead><tbody><tr><td><strong>数据漂移 Data Drift</strong></td><td>输入数据的统计分布变了</td><td>PSI（Population Stability Index）</td><td>用户搜索词分布变化（疫情期搜&quot;口罩&quot;暴增）</td></tr><tr><td><strong>概念漂移 Concept Drift</strong></td><td>输入和输出的关系变了</td><td>在线上新数据上重新评估</td><td>&quot;快了&quot;在快递场景以前是正面评价，现在可能是抱怨（和&quot;明天就到&quot;对比）</td></tr></tbody></table><p><strong>PM 的工作</strong>：</p><ol><li>定义需要监控的特征（核心输入字段、预测置信度分布、各类别占比）</li><li>设定告警阈值（PSI &gt; 0.25 触发告警，PSI &gt; 0.3 触发自动再训练）</li><li>定期 review 监控报告（建议频率：周级）</li></ol><h3 id="_4-2-再训练触发机制" tabindex="-1">4.2 再训练触发机制 <a class="header-anchor" href="#_4-2-再训练触发机制" aria-label="Permalink to &quot;4.2 再训练触发机制&quot;">​</a></h3><table tabindex="0"><thead><tr><th>触发方式</th><th>优点</th><th>缺点</th><th>适用场景</th></tr></thead><tbody><tr><td><strong>定时触发</strong></td><td>可预测、可控</td><td>可能在不需要时浪费资源</td><td>稳定性要求高的场景（金融风控）</td></tr><tr><td><strong>数据量触发</strong></td><td>不浪费</td><td>可能很久不触发</td><td>数据增长较慢的场景</td></tr><tr><td><strong>性能触发</strong></td><td>最精准</td><td>需要有完善的监控</td><td>高并发场景（推荐系统）</td></tr><tr><td><strong>事件触发</strong></td><td>响应业务变化</td><td>需要人工判断</td><td>业务规则变更时</td></tr></tbody></table><hr><h2 id="五、面试追问合集" tabindex="-1">五、面试追问合集 <a class="header-anchor" href="#五、面试追问合集" aria-label="Permalink to &quot;五、面试追问合集&quot;">​</a></h2><h3 id="q1-标注数据不够怎么办" tabindex="-1">Q1: 标注数据不够怎么办？ <a class="header-anchor" href="#q1-标注数据不够怎么办" aria-label="Permalink to &quot;Q1: 标注数据不够怎么办？&quot;">​</a></h3><details class="details custom-block"><summary>答案</summary><p>这是 AI PM 最常面对的现实问题——标注数据永远不够。应对策略从易到难：</p><ol><li><p><strong>数据增强</strong>：对现有样本做微调——文本分类可以做同义词替换、回译（中→英→中），CV 可以做旋转、裁剪、亮度调整。成本几乎为零，但效果有限，大约能提升 2-5% 准确率。</p></li><li><p><strong>主动学习</strong>：让模型帮你找出&quot;最不确定&quot;的样本，优先标注那些——而不是随机标注。我们项目用了这个方法，标注效率提升了约 40%。</p></li><li><p><strong>Few-shot Learning + 大模型辅助标注</strong>：用 GPT-4o 先自动标注一批数据，然后人审核修正——准确率虽然达不到纯人工标注的水平（GPT-4o 自动标注大概 85-90%，人工可以到 95%+），但速度和成本是人工的 1/10。对于快速验证阶段足够了。</p></li><li><p><strong>迁移学习</strong>：在公开的大数据集上预训练，然后在你自己的小数据集上微调——这是 Deep Learning 时代最标准的做法。</p></li></ol></details><h3 id="q2-如何跟算法团队沟通模型效果不理想的问题" tabindex="-1">Q2: 如何跟算法团队沟通模型效果不理想的问题？ <a class="header-anchor" href="#q2-如何跟算法团队沟通模型效果不理想的问题" aria-label="Permalink to &quot;Q2: 如何跟算法团队沟通模型效果不理想的问题？&quot;">​</a></h3><details class="details custom-block"><summary>答案</summary><p>很多 PM 会犯的错误是直接说&quot;这个模型不准&quot;——算法工程师听了只会觉得&quot;你说了等于没说&quot;。</p><p>正确的沟通方式是用数据和案例说话：</p><p>❌ &quot;模型太差了吧&quot; ✅ &quot;我跑了 100 条测试用例，发现模型在以下三类 case 上准确率偏低：1) 用户用缩写表达时（如&#39;jd&#39;→京东），准确率只有 65%；2) 用户输入有错别字时，准确率 70%；3) 中英文混输时，准确率 72%。这是具体的 Bad Case 列表，你看是不是数据层面的问题还是模型架构的问题？&quot;</p><p>关键是要提供<strong>可复现的 Bad Case + 量化的影响范围</strong>。算法看到&quot;3 类 Bad Case 影响了约 15% 的流量&quot;，就知道优先度的方向了。</p></details><h3 id="q3-上线后模型效果下降-怎么排查" tabindex="-1">Q3: 上线后模型效果下降，怎么排查？ <a class="header-anchor" href="#q3-上线后模型效果下降-怎么排查" aria-label="Permalink to &quot;Q3: 上线后模型效果下降，怎么排查？&quot;">​</a></h3><details class="details custom-block"><summary>答案</summary><p>标准排查流程：</p><ol><li><p><strong>确认是不是真的下降</strong>：噪音波动还是趋势性下降？看 2-4 周的监控趋势，别被单日波动吓到。</p></li><li><p><strong>看数据分布变化</strong>（Data Drift）：拉一下线上数据和训练数据的特征分布对比。如果某些特征的分布偏移明显，就是数据漂移。</p></li><li><p><strong>看特定人群/场景</strong>：是不是只在某些用户群体或时间段下降了？比如只在 Android 用户上降了——可能是某个端的数据格式有问题。</p></li><li><p><strong>回滚到上一个稳定版本</strong>：先止血（如果影响业务指标的话），再慢慢排查。</p></li><li><p><strong>触发再训练</strong>：如果确认是数据漂移，用最近的数据微调模型或者直接触发一次完整的再训练。</p></li></ol><p><strong>最容易忽略的排查方向</strong>：不是模型变了，是数据变了。业务规则改了、用户群体变了、营销活动导致了异常流量——这些是 PM 的知识域，算法不一定知道。</p></details><hr><h2 id="五、llm-时代的数据前沿话题-✨" tabindex="-1">五、LLM 时代的数据前沿话题 ✨ <a class="header-anchor" href="#五、llm-时代的数据前沿话题-✨" aria-label="Permalink to &quot;五、LLM 时代的数据前沿话题 ✨&quot;">​</a></h2><h3 id="_5-1-合成数据-synthetic-data" tabindex="-1">5.1 合成数据（Synthetic Data） <a class="header-anchor" href="#_5-1-合成数据-synthetic-data" aria-label="Permalink to &quot;5.1 合成数据（Synthetic Data）&quot;">​</a></h3><p>合成数据是用 AI 生成的数据代替/补充人工标注数据。2024-2025 年这已成为 AI 产品研发的标准实践。</p><p><strong>PM 需要知道的核心三点：</strong></p><p><strong>① 什么时候适合用合成数据？</strong></p><table tabindex="0"><thead><tr><th>适合</th><th>不适合</th></tr></thead><tbody><tr><td>标注数据不够（可用 GPT-4o 自动标注 + 人工审核）</td><td>需要精确领域知识（如医学诊断）</td></tr><tr><td>多样化的用户表达方式生成（&quot;退货&quot;的 100 种说法）</td><td>数据质量要求极高且不能被&quot;机器思维&quot;污染</td></tr><tr><td>快速冷启动（模型还没数据积累的阶段）</td><td>模型的判断可能带有训练数据的偏见</td></tr></tbody></table><p><strong>② 合成数据的工作流：</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Step 1: 用 GPT-4o 为 200 条种子数据自动生成标签</span></span>
<span class="line"><span>Step 2: 人工审核前 50-100 条，如果准确率 &gt; 90% → 批量放行</span></span>
<span class="line"><span>Step 3: 对不准确的部分，细化标注规范 → 让 GPT-4o 重新生成</span></span>
<span class="line"><span>Step 4: 最终数据集 = GPT-4o 标注 + 人工修正 = 成本是纯人工的 1/5</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p><strong>③ 合成数据的风险：</strong></p><ul><li>模型自我循环——用 GPT-4o 标注的数据训练小模型，小模型的偏差来自 GPT-4o，受限于 GPT-4o 的上限</li><li>&quot;幻觉传染&quot;——GPT-4o 如果在一类 Case 上系统性给错标签，后面的模型全学歪</li></ul><p><strong>PM 对策</strong>：合成数据必须保持一定比例（≥20%）的人工抽查验证。关键场景（医疗/金融/法律）的合成数据必须 100% 人工审核。</p><h3 id="_5-2-用户反馈数据——被低估的金矿" tabindex="-1">5.2 用户反馈数据——被低估的金矿 <a class="header-anchor" href="#_5-2-用户反馈数据——被低估的金矿" aria-label="Permalink to &quot;5.2 用户反馈数据——被低估的金矿&quot;">​</a></h3><p>用户反馈数据有两种类型，AI PM 需要区别对待：</p><table tabindex="0"><thead><tr><th>反馈类型</th><th>收集方式</th><th>数据价值</th><th>PM 需要的</th></tr></thead><tbody><tr><td><strong>显式反馈</strong></td><td>赞/踩按钮、打分、举报</td><td>明确但稀疏（&lt; 5% 用户会点）</td><td>每个&quot;踩&quot;都是一条 Bad Case，值得人工复查</td></tr><tr><td><strong>隐式反馈</strong></td><td>点击、停留时长、复制、分享、重复提问</td><td>丰富但噪声大</td><td>用户复制了 AI 回答 = 有用；用户 30 秒内重复问了类似问题 = AI 没解决</td></tr></tbody></table><p><strong>一个实战洞察</strong>：某 AI 客服项目发现，用户点赞率 85%，但隐式反馈数据（重复提问率）显示只有 68% 的问题被真正解决。<strong>显式反馈是&quot;礼貌性点赞&quot;，隐式反馈才是&quot;真实的满意度&quot;</strong>。AI PM 必须同时看两组数据。</p><h3 id="_5-3-数据版本管理简介" tabindex="-1">5.3 数据版本管理简介 <a class="header-anchor" href="#_5-3-数据版本管理简介" aria-label="Permalink to &quot;5.3 数据版本管理简介&quot;">​</a></h3><p>当项目涉及多轮迭代和团队协作时，数据版本管理变得必要。以下是 PM 级别的理解：</p><table tabindex="0"><thead><tr><th>工具</th><th>定位</th><th>PM 需要知道的</th></tr></thead><tbody><tr><td><strong>DVC</strong></td><td>数据版本控制（类似 Git for Data）</td><td>知道标注数据每次更新都有版本记录，可以回溯</td></tr><tr><td><strong>LakeFS</strong></td><td>数据湖版本管理</td><td>了解&quot;分支&quot;概念——在数据分支上做标注实验，满意后 merge 到主分支</td></tr><tr><td><strong>Git LFS</strong></td><td>Git 的大文件扩展</td><td>用于管理 Prompt 模板和评测集的版本</td></tr></tbody></table><p><strong>PM 不需要会用这些工具，但需要知道它们解决的问题</strong>：标注数据 V1.0 和 V1.1 之间到底改了哪些样本？谁改的？为什么？能不能回滚？——如果回答不了这些问题，数据版本管理就是刚需。</p><hr><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="./tech-basics">AI 技术基础</a></li><li><a href="./product-design">AI 产品设计</a></li><li><a href="./evaluation">AI 评估体系</a></li><li><a href="./case-study">实战案例：智能客服全流程</a></li><li><a href="./interview">AI PM 面试高频题</a></li></ul>`,45))])}const P=i(u,[["render",p]]);export{m as __pageData,P as default};
